import 'dart:math' as math;import 'hvac_standards.dart';import 'unit_conversion.dart';
enum PipeVelocityJudgement { recommended, lowButUsable, overspeed }
class PipeCandidate {final HvacStandardPipe pipe;final double velocityMps;final PipeVelocityJudgement judgement;const PipeCandidate(this.pipe,this.velocityMps,this.judgement);}class PipeSizingResult {final PipeCandidate? recommended;final List<PipeCandidate> candidates;final String message;const PipeSizingResult({required this.recommended,required this.candidates,required this.message});}
class PipeSizing {static const double minRecommended=1.2;static const double maxVelocity=3.0;static double areaM2(double mm){final d=mm/1000;return math.pi*d*d/4;}static PipeSizingResult suggest(double lpm){if(!lpm.isFinite||lpm<=0){return const PipeSizingResult(recommended:null,candidates:[],message:'請輸入大於 0 的流量。');}final q=UnitConversion.lpmToM3s(lpm);final all=hvacStandardPipes.map((p){final v=q/areaM2(p.insideDiameterMm);final j=v>maxVelocity?PipeVelocityJudgement.overspeed:(v<minRecommended?PipeVelocityJudgement.lowButUsable:PipeVelocityJudgement.recommended);return PipeCandidate(p,v,j);}).toList();PipeCandidate? rec;for(final c in all){if(c.velocityMps<=maxVelocity){rec=c;break;}}if(rec==null){return PipeSizingResult(recommended:null,candidates:all.reversed.take(5).toList().reversed.toList(),message:'超出表內管徑，請分管或加大管徑。');}final i=all.indexOf(rec);final s=(i-1).clamp(0,all.length-1);final e=(i+2).clamp(0,all.length);return PipeSizingResult(recommended:rec,candidates:all.sublist(s,e),message:rec.velocityMps<minRecommended?'偏低但可用，可能管徑偏大':'建議');}}
